{"content": "class_name SkillManager
extends Node
## 技能管理器 — 4 槽位 + 输入绑定 + 按类型分发执行
## 挂载到任意施法实体

## ── 绑定类型 ──
enum BindType {
	LEFT_HAND,   ## 鼠标左键
	RIGHT_HAND,  ## 鼠标右键
	KEY_1,       ## 数字键 1
	KEY_2,       ## 数字键 2
	KEY_3,       ## 数字键 3
	KEY_4,       ## 数字键 4
}

const MAX_SLOTS := 4

## ── 信号 ──
signal slot_changed(slot_index: int)
signal cooldown_changed(slot_index: int, remaining: float, total: float)
signal skill_used(slot_index: int, skill: SkillData)

## ── 槽位数据 ──
var _slots: Array[Dictionary] = []


func _ready() -> void:
	_slots.resize(MAX_SLOTS)
	for i in range(MAX_SLOTS):
		_slots[i] = {"skill": null, "bind": -1, "cooldown": 0.0}


func _process(delta: float) -> void:
	for i in range(MAX_SLOTS):
		var cd: float = _slots[i]["cooldown"]
		if cd > 0.0:
			cd = maxf(0.0, cd - delta)
			_slots[i]["cooldown"] = cd
			var skill: SkillData = _slots[i]["skill"]
			if skill:
				cooldown_changed.emit(i, cd, skill.cooldown)


## ── 装备管理 ──

func initialize(pool: SkillPool, default_binds: Array = []) -> void:
	"""从技能池加载技能到槽位。default_binds 可选指定每个槽的绑定类型。"""
	for i in range(MAX_SLOTS):
		_slots[i] = {"skill": null, "bind": -1, "cooldown": 0.0}
		if pool and i < pool.skills.size():
			_slots[i]["skill"] = pool.skills[i]
			_slots[i]["bind"] = default_binds[i] if i < default_binds.size() else i + 2  # KEY_1..KEY_4
			slot_changed.emit(i)


func equip_to_slot(slot_index: int, skill: SkillData, bind: int = -1) -> void:
	if slot_index < 0 or slot_index >= MAX_SLOTS:
		return
	_slots[slot_index]["skill"] = skill
	_slots[slot_index]["bind"] = bind if bind >= 0 else slot_index + 2
	_slots[slot_index]["cooldown"] = 0.0
	slot_changed.emit(slot_index)


func unequip_slot(slot_index: int) -> SkillData:
	if slot_index < 0 or slot_index >= MAX_SLOTS:
		return null
	var old: SkillData = _slots[slot_index]["skill"]
	_slots[slot_index] = {"skill": null, "bind": -1, "cooldown": 0.0}
	slot_changed.emit(slot_index)
	return old


## ── 查询 ──

func get_slot(slot_index: int) -> Dictionary:
	if slot_index < 0 or slot_index >= MAX_SLOTS:
		return {"skill": null, "bind": -1, "cooldown": 0.0}
	return _slots[slot_index]


func can_use(slot_index: int) -> bool:
	if slot_index < 0 or slot_index >= MAX_SLOTS:
		return false
	return _slots[slot_index]["skill"] != null and _slots[slot_index]["cooldown"] <= 0.0


## 查找哪个槽位绑定了指定输入动作（"attack"/"skill"/"skill_1".."skill_4"）
func find_slot_for_action(action: String) -> int:
	var bind: int = _action_to_bind(action)
	if bind < 0:
		return -1
	for i in range(MAX_SLOTS):
		if _slots[i]["bind"] == bind and _slots[i]["skill"] != null:
			return i
	return -1


func _action_to_bind(action: String) -> int:
	match action:
		"attack":    return BindType.LEFT_HAND
		"skill":     return BindType.RIGHT_HAND
		"skill_1":   return BindType.KEY_1
		"skill_2":   return BindType.KEY_2
		"skill_3":   return BindType.KEY_3
		"skill_4":   return BindType.KEY_4
	return -1


func get_cooldown(slot_index: int) -> float:
	if slot_index < 0 or slot_index >= MAX_SLOTS:
		return 0.0
	return _slots[slot_index]["cooldown"]


func get_cooldown_total(slot_index: int) -> float:
	var skill: SkillData = _slots[slot_index]["skill"] if slot_index >= 0 and slot_index < MAX_SLOTS else null
	return skill.cooldown if skill else 1.0


## ── 释放技能（核心分发） ──

func use_slot(slot_index: int, caster: Node2D, direction: Vector2) -> bool:
	if slot_index < 0 or slot_index >= MAX_SLOTS:
		return false

	var slot = _slots[slot_index]
	var skill: SkillData = slot["skill"]
	if not skill:
		return false
	if slot["cooldown"] > 0.0:
		return false

	# MP 检查
	var mana := caster.get_node_or_null("ManaComponent") as ManaComponent
	if mana and skill.mp_cost > 0 and not mana.use_mp(skill.mp_cost):
		return false

	# 按类型分发
	var ok := false
	match skill.skill_type:
		SkillData.SkillType.PROJECTILE:
			ok = _execute_projectile(skill, caster, direction)
		SkillData.SkillType.BUFF:
			ok = _execute_buff(skill, caster)
		SkillData.SkillType.AOE:
			ok = _execute_aoe(skill, caster, direction)
		SkillData.SkillType.DASH:
			ok = _execute_dash(skill, caster, direction)

	if not ok:
		# 失败了就退还 MP
		if mana and skill.mp_cost > 0:
			mana.restore_mp(skill.mp_cost)
		return false

	# 设置冷却
	slot["cooldown"] = skill.cooldown
	cooldown_changed.emit(slot_index, skill.cooldown, skill.cooldown)
	skill_used.emit(slot_index, skill)
	return true


## ── 执行器 ──

func _execute_projectile(skill: SkillData, caster: Node2D, direction: Vector2) -> bool:
	var scene := skill.projectile_scene if skill.projectile_scene else skill.scene
	if not scene:
		return false

	var instance := scene.instantiate() as Node2D
	caster.get_tree().current_scene.add_child(instance)
	instance.global_position = caster.global_position + direction * skill.cast_distance

	if instance is Projectile:
		var proj := instance as Projectile
		proj.set_direction(direction)
		proj.set_caster(caster)
		proj.damage = skill.damage
		proj.speed = skill.projectile_speed
	return true


func _execute_buff(skill: SkillData, caster: Node2D) -> bool:
	if not skill.buff_resource:
		return false

	var buff_manager := caster.get_node_or_null("BuffManager")
	if not buff_manager:
		return false

	# 复制一份 Buff 以支持覆盖 duration
	var buff := skill.buff_resource.duplicate() as Buff
	if skill.buff_duration > 0:
		buff.duration = skill.buff_duration
	buff_manager.apply_buff(buff)
	return true


func _execute_aoe(skill: SkillData, caster: Node2D, direction: Vector2) -> bool:
	if not skill.aoe_scene:
		return false

	var instance := skill.aoe_scene.instantiate() as Node2D
	caster.get_tree().current_scene.add_child(instance)
	instance.global_position = caster.global_position + direction * skill.aoe_radius

	# AOE 场景应自毁（如 Area2D + timer）
	if "damage" in instance:
		instance.damage = skill.damage
	if instance.has_method("set_caster"):
		instance.set_caster(caster)
	return true


func _execute_dash(skill: SkillData, caster: Node2D, direction: Vector2) -> bool:
	if not caster is CharacterBody2D:
		return false

	var body := caster as CharacterBody2D
	var tween := body.create_tween()
	tween.tween_property(body, "global_position",
		body.global_position + direction * skill.dash_distance,
		skill.dash_distance / skill.dash_speed
	).set_ease(Tween.EASE_OUT).set_trans(Tween.TRANS_QUAD)
	return true


## ── 兼容旧 API（逐步淘汰） ──

func use_skill(_slot: int, caster: Node2D, direction: Vector2) -> bool:
	return use_slot(0, caster, direction)


func get_cooldown_remaining(slot_index: int) -> float:
	return get_cooldown(slot_index)
